const data = $input.first().json;
const results = data.shopping_results || [];
const termoBuscado = data.search_parameters?.q || '';

const precoMin = parseFloat($('Formulário de Busca').first().json['Preço Mínimo R$'] || 0);
const precoMax = parseFloat($('Formulário de Busca').first().json['Preço Máximo R$'] || 999999);

const produtos = results.map((item, idx) => {
  // ScaleSerp retorna price como NUMBER — tratar corretamente
  let precoNumero = 0;
  let precoFormatado = '';

  if (item.price_parsed?.value) {
    precoNumero = item.price_parsed.value;
    precoFormatado = item.price_raw || ('R$ ' + precoNumero.toFixed(2));
  } else if (typeof item.price === 'number') {
    precoNumero = item.price;
    precoFormatado = item.price_raw || ('R$ ' + item.price.toLocaleString('pt-BR', {minimumFractionDigits: 2}));
  } else if (typeof item.price === 'string') {
    precoFormatado = item.price;
    precoNumero = parseFloat(
      item.price.replace(/R$\s*/g, '').replace(/\./g, '').replace(',', '.')
    ) || 0;
  }

  // Links — ScaleSerp pode retornar em campos diferentes
  const link = item.link || item.product_link || item.shopping_link || '';

  // Merchant ja vem direto do ScaleSerp — mais confiável que scraping
  const loja = item.merchant || item.source || 'Desconhecido';

  return {
    nome: item.title || '',
    preco_formatado: precoFormatado,
    preco_numero: precoNumero,
    link,
    loja_google: loja,
    imagem: (item.image || '').startsWith('data:') ? '' : (item.image || item.thumbnail || ''),
    rating: item.rating || null,
    reviews: item.reviews || null,
    termo_buscado: termoBuscado,
    posicao: idx + 1
  };
}).filter(p => {
  if (!p.nome) return false;
  if (precoMin > 0 && p.preco_numero < precoMin) return false;
  if (precoMax < 999999 && p.preco_numero > precoMax) return false;
  return true;
});

if (produtos.length === 0) {
  throw new Error('Nenhum produto encontrado. Ajuste os filtros ou o termo de busca.');
}

return produtos.map(p => ({ json: p }));

const resposta = $input.first().json;
const conteudo = resposta.choices?.[0]?.message?.content || "{}";

let analise = {};
try {
  const limpo = conteudo.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analise = JSON.parse(limpo);
} catch(e) {
  analise = {
    match_score: 0,
    is_compatible: false,
    categoria: "erro_parse",
    nome_normalizado: "",
    motivo: "Erro ao processar IA: " + e.message
  };
}

const produto = $('Loop - 1 por Vez').item.json;

return [{
  json: {
    ...produto,
    match_score: analise.match_score ?? 0,
    is_compatible: analise.is_compatible ?? false,
    categoria_match: analise.categoria || "",
    nome_normalizado: analise.nome_normalizado || produto.nome,
    motivo_match: analise.motivo || ""
  }
}];

const produto = $('Score >= 60?').item.json;
const link = produto.link || '';

// Sem link: usa merchant do ScaleSerp direto
if (!link) {
  return [{
    json: {
      ...produto,
      marketplace: produto.loja_google || 'Desconhecido',
      vendedor: produto.loja_google || 'Não identificado',
      data_captura: new Date().toISOString().slice(0, 19).replace('T', ' ')
    }
  }];
}

const html = $input.first().json.data || $input.first().json.body || '';

// Fallback sempre é o merchant do ScaleSerp
let vendedor = produto.loja_google || 'Não identificado';
let marketplace = 'Outros';

function matchFirst(html, padroes) {
  for (const p of padroes) {
    const m = html.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return null;
}

if (link.includes('mercadolivre.com.br') || link.includes('mercadolibre.com')) {
  marketplace = 'Mercado Livre';
  const found = matchFirst(html, [
    new RegExp('"nickname"\\s*:\\s*"([^"]+)"'),
    new RegExp('class="ui-pdp-seller__header__title"[^>]*>\\s*([^<]+)'),
    new RegExp('Vendido por\\s*<[^>]*>([^<]+)')
  ]);
  if (found) vendedor = found;

} else if (link.includes('amazon.com.br')) {
  marketplace = 'Amazon';
  const found = matchFirst(html, [
    new RegExp('id="sellerProfileTriggerId"[^>]*>([^<]+)'),
    new RegExp('"merchant"\\s*:\\s*"([^"]+)"'),
    new RegExp('Vendido por:\\s*<[^>]*>([^<]+)')
  ]);
  if (found) vendedor = found;
  else if (html.includes('Amazon.com.br')) vendedor = 'Amazon.com.br';

} else if (link.includes('magazineluiza.com.br') || link.includes('magalu.com')) {
  marketplace = 'Magazine Luiza';
  const found = matchFirst(html, [
    new RegExp('"sellerName"\\s*:\\s*"([^"]+)"'),
    new RegExp('data-seller-name="([^"]+)"'),
    new RegExp('class="[^"]*seller-name[^"]*"[^>]*>([^<]+)')
  ]);
  if (found) vendedor = found;

} else if (link.includes('casasbahia.com.br')) {
  marketplace = 'Casas Bahia';
  const found = matchFirst(html, [
    new RegExp('"sellerName"\\s*:\\s*"([^"]+)"'),
    new RegExp('data-testid="seller-name"[^>]*>([^<]+)')
  ]);
  if (found) vendedor = found;

} else if (link.includes('shopee.com.br')) {
  marketplace = 'Shopee';
  const found = matchFirst(html, [
    new RegExp('"shopName"\\s*:\\s*"([^"]+)"'),
    new RegExp('"shop_name"\\s*:\\s*"([^"]+)"')
  ]);
  if (found) vendedor = found;

} else if (link.includes('americanas.com.br')) {
  marketplace = 'Americanas';
  const found = matchFirst(html, [new RegExp('"sellerName"\\s*:\\s*"([^"]+)"')]);
  if (found) vendedor = found;

} else {
  marketplace = produto.loja_google || 'Outros';
}

return [{
  json: {
    ...produto,
    marketplace,
    vendedor,
    data_captura: new Date().toISOString().slice(0, 19).replace('T', ' ')
  }
}];
